import React, { Component } from 'react';
import { Link as ScrollLink } from 'react-scroll';
import { Box, AppBar, Toolbar, Typography, Container, Grid, Button, Card, CardContent } from '@mui/material';
import { FaGithub, FaLinkedin, FaTwitter } from 'react-icons/fa';
import { Slide } from 'react-reveal';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';

// Creating a theme for consistent design
const theme = createTheme({
  typography: {
    fontFamily: 'Roboto, sans-serif',
    h1: {
      fontSize: '4rem',
      fontWeight: 'bold',
    },
    h2: {
      fontSize: '2.5rem',
      fontWeight: 'bold',
    },
    body1: {
      fontSize: '1.1rem',
    },
  },
});

// Styled AppBar for sticky navigation
const StyledAppBar = styled(AppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
  backgroundColor: 'transparent',
  boxShadow: 'none',
  position: 'fixed',
  top: 0,
  left: 0,
  right: 0,
  padding: '0 20px',
}));

class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      selectedTab: 'All',
      projects: {
        All: [
          { title: 'Project 1', description: 'Description for project 1', link: 'https://github.com/yourusername/project1' },
          { title: 'Project 2', description: 'Description for project 2', link: 'https://github.com/yourusername/project2' },
        ],
        'WEB APPS': [
          { title: 'Web App 1', description: 'A web app project description', link: 'https://github.com/yourusername/webapp1' },
        ],
      }
    };
  }

  render() {
    const { projects, selectedTab } = this.state;

    return (
      <ThemeProvider theme={theme}>
        <Box sx={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
          {/* Sticky Navigation Bar */}
          <StyledAppBar position="sticky">
            <Toolbar>
              <Typography variant="h6" sx={{ flexGrow: 1 }}>My Portfolio</Typography>
              <Box sx={{ display: 'flex', justifyContent: 'flex-end', gap: '20px' }}>
                <ScrollLink to="projects" smooth={true} duration={500}>
                  <Button color="inherit" sx={{ color: '#fff', textTransform: 'uppercase', fontWeight: 'bold' }}>Projects</Button>
                </ScrollLink>
                <ScrollLink to="contact" smooth={true} duration={500}>
                  <Button color="inherit" sx={{ color: '#fff', textTransform: 'uppercase', fontWeight: 'bold' }}>Contact</Button>
                </ScrollLink>
              </Box>
            </Toolbar>
          </StyledAppBar>

          {/* Hero Section */}
          <Box sx={{ 
            background: 'linear-gradient(135deg, rgba(0, 0, 0, 0.5) 50%, rgba(0, 0, 0, 0.8) 100%), url(https://via.placeholder.com/1500)', 
            backgroundSize: 'cover', 
            backgroundPosition: 'center',
            height: '100vh',
            display: 'flex', 
            justifyContent: 'center',
            alignItems: 'center',
            textAlign: 'center',
            color: '#fff',
            padding: '20px' 
          }}>
            <Slide bottom>
              <div>
                <Typography variant="h1" sx={{ marginBottom: '20px' }}>
                  Find. Think. Solve.
                </Typography>
                <Typography variant="h2" sx={{ marginBottom: '30px' }}>
                  A Passionate Web Developer
                </Typography>
                <Button variant="contained" color="primary" sx={{ fontWeight: 'bold', padding: '10px 30px' }}>Get in Touch</Button>
              </div>
            </Slide>
          </Box>

          {/* Projects Section */}
          <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
            <Typography variant="h2" gutterBottom sx={{ textAlign: 'center' }}>My Projects</Typography>
            <Grid container spacing={3}>
              {projects[selectedTab].map((project, index) => (
                <Grid item xs={12} sm={6} md={4} key={index}>
                  <Card sx={{ boxShadow: 3, transition: 'transform 0.3s ease', '&:hover': { transform: 'scale(1.05)' } }}>
                    <CardContent>
                      <Typography variant="h5" sx={{ marginBottom: '10px' }}>{project.title}</Typography>
                      <Typography variant="body1" sx={{ marginBottom: '15px' }}>{project.description}</Typography>
                      <Button href={project.link} target="_blank" variant="contained" color="primary">
                        View Project
                      </Button>
                    </CardContent>
                  </Card>
                </Grid>
              ))}
            </Grid>
          </Container>

          {/* Contact Section */}
          <Container id="contact" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
            <Typography variant="h2" gutterBottom sx={{ textAlign: 'center' }}>Contact Me</Typography>
            <form>
              <input type="text" placeholder="Your Name" required style={{ padding: '10px', marginBottom: '10px', width: '100%' }} />
              <input type="email" placeholder="Your Email" required style={{ padding: '10px', marginBottom: '10px', width: '100%' }} />
              <textarea placeholder="Your Message" required style={{ padding: '10px', width: '100%', height: '150px' }}></textarea>
              <Button type="submit" variant="contained" color="primary" sx={{ mt: 2 }}>Send Message</Button>
            </form>
          </Container>

          {/* Footer with Social Media Links */}
          <Box sx={{ position: 'fixed', bottom: 20, right: 20, display: 'flex', flexDirection: 'column' }}>
            <Button href="https://github.com/yourusername" target="_blank" sx={{ mb: 2 }}>
              <FaGithub size={30} />
            </Button>
            <Button href="https://www.linkedin.com/in/yourusername/" target="_blank" sx={{ mb: 2 }}>
              <FaLinkedin size={30} />
            </Button>
            <Button href="https://twitter.com/yourusername" target="_blank">
              <FaTwitter size={30} />
            </Button>
          </Box>
        </Box>
      </ThemeProvider>
    );
  }
}

export default Dashboard;
